import React from 'react';

const AboutMe = () => {
  return (
    <section>
      <h2 className="text-2xl font-semibold text-blue-600">About Me</h2>
      <p className="mt-3 text-lg">
        Hi! I'm Janelle Villanueva, a passionate web developer who enjoys building clean and user-friendly applications.
      </p>
    </section>
  );
};

export default AboutMe;
